func (t *Tree) startParse(funcs []map[string]any, lex *lexer, treeSet map[string]*Tree) {
	t.Root = nil
	t.lex = lex
	t.vars = []string{"$"}
	t.funcs = funcs
	t.treeSet = treeSet
	lex.options = lexOptions{
		emitComment:	t.Mode&ParseComments != 0,
		breakOK:	!t.hasFunction("break"),
		continueOK:	!t.hasFunction("continue"),
	}
}
